import React, { useState, useEffect } from "react";
import { Form, Button, Col, Row, Alert, Spinner } from "react-bootstrap";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import Header from "../../components/Headers/Header";
import ReactQuill from "react-quill";
import "react-quill/dist/quill.snow.css";

const EditDrug = () => {
    const { id } = useParams();
    const navigate = useNavigate();

    const [medicineTypes, setMedicineTypes] = useState([]);
    const [drug, setDrug] = useState({
        medicine_code: "",
        medicine_name: "",
        medicine_type_id: "",
        medicine_type_name: "",
        price: "",
        unit: "",
        description: "",
    });

    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState(null);

    // Fetch medicine data and medicine types
    useEffect(() => {
        const fetchData = async () => {
            setLoading(true);
            setError(null);
            try {
                // Fetch medicine details
                const medicineResponse = await axios.get(`http://localhost:5001/api/medicine/${id}`);

                // Get medicine type list (assuming you have this endpoint)
                // If you don't have this endpoint, you'll need to create it
                const typesResponse = await axios.get("http://localhost:5001/api/medicineType");

                // Set medicine data
                if (medicineResponse.data) {
                    setDrug({
                        medicine_code: medicineResponse.data.medicine_code || "",
                        medicine_name: medicineResponse.data.medicine_name || "",
                        medicine_type_id: medicineResponse.data.medicine_type_id ?
                            medicineResponse.data.medicine_type_id.toString() : "",
                        medicine_type_name: medicineResponse.data.medicine_type_name || "",
                        price: medicineResponse.data.price ?
                            medicineResponse.data.price.toString() : "",
                        unit: medicineResponse.data.unit || "",
                        description: medicineResponse.data.description || "",
                    });
                } else {
                    setError("Invalid medicine data.");
                }

                // Set medicine types
                if (typesResponse.data && typesResponse.data.data) {
                    setMedicineTypes(typesResponse.data.data);
                }
            } catch (error) {
                console.error("Error fetching data:", error);
                setError("Medicine not found or error loading data.");
            } finally {
                setLoading(false);
            }
        };

        fetchData();
    }, [id]);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setDrug((prev) => ({ ...prev, [name]: value }));
    };

    const handleDescriptionChange = (value) => {
        setDrug((prev) => ({ ...prev, description: value }));
    };

    const handleUpdate = async (e) => {
        e.preventDefault();

        if (!drug.medicine_code || !drug.medicine_name || !drug.medicine_type_id || !drug.price || !drug.unit) {
            alert("Please fill all required fields!");
            return;
        }

        setSaving(true);
        try {
            const updateData = {
                medicine_code: drug.medicine_code,
                medicine_name: drug.medicine_name,
                medicine_type_id: drug.medicine_type_id ? parseInt(drug.medicine_type_id) : null,
                price: drug.price ? parseInt(drug.price) : null,
                unit: drug.unit,
                description: drug.description,
            };

            await axios.put(`http://localhost:5001/api/medicine/${id}`, updateData);
            alert("Update successful!");
            navigate("/drug");
        } catch (error) {
            alert(`Update failed! Error: ${error.response?.data?.message || error.message}`);
        } finally {
            setSaving(false);
        }
    };

    const handleCancel = () => {
        navigate("/drug");
    };

    if (loading) {
        return (
            <>
                <Header />
                <div className="container mt-4 text-center">
                    <Spinner animation="border" role="status">
                        <span className="visually-hidden">Loading...</span>
                    </Spinner>
                    <p>Loading medicine data...</p>
                </div>
            </>
        );
    }

    if (error) {
        return (
            <>
                <Header />
                <div className="container mt-4">
                    <Alert variant="danger">{error}</Alert>
                    <Button variant="primary" onClick={() => navigate("/drug")}>
                        Return to Drug List
                    </Button>
                </div>
            </>
        );
    }

    return (
        <>
            <Header />
            <div className="container mt-4">
                <h4 className="mb-4" style={{ fontSize: "28px", fontWeight: "bold" }}>Edit Drug</h4>
                <Form onSubmit={handleUpdate}>
                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineCode">
                                <Form.Label>Drug Code *</Form.Label>
                                <Form.Control
                                    type="text"
                                    name="medicine_code"
                                    value={drug.medicine_code}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="medicineName">
                                <Form.Label>Drug Name *</Form.Label>
                                <Form.Control
                                    type="text"
                                    name="medicine_name"
                                    value={drug.medicine_name}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>
                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineTypeId">
                                <Form.Label>Drug Type *</Form.Label>
                                <Form.Select
                                    name="medicine_type_id"
                                    value={drug.medicine_type_id}
                                    onChange={handleChange}
                                    required
                                >
                                    <option value="">Select Drug Type</option>
                                    {medicineTypes.map((type) => (
                                        <option key={type.id} value={type.id}>
                                            {type.medicine_type_name}
                                        </option>
                                    ))}
                                </Form.Select>
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="drugPrice">
                                <Form.Label>Price (VND) *</Form.Label>
                                <Form.Control
                                    type="number"
                                    name="price"
                                    value={drug.price}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>
                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="drugUnit">
                                <Form.Label>Unit *</Form.Label>
                                <Form.Control
                                    type="text"
                                    name="unit"
                                    value={drug.unit}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>
                    <Form.Group controlId="drugDescription" className="mb-4">
                        <Form.Label>Description *</Form.Label>
                        <ReactQuill
                            theme="snow"
                            value={drug.description}
                            onChange={handleDescriptionChange}
                            style={{ height: "200px", marginBottom: "50px" }}
                        />
                    </Form.Group>
                    <div className="d-flex justify-content-end mt-5">
                        <Button variant="secondary" onClick={handleCancel} className="me-2">
                            Cancel
                        </Button>
                        <Button
                            variant="primary"
                            type="submit"
                            disabled={saving}
                        >
                            {saving ? (
                                <>
                                    <Spinner
                                        as="span"
                                        animation="border"
                                        size="sm"
                                        role="status"
                                        aria-hidden="true"
                                        className="me-2"
                                    />
                                    Saving...
                                </>
                            ) : (
                                "Save Changes"
                            )}
                        </Button>
                    </div>
                </Form>
            </div>
        </>
    );
};

export default EditDrug;
